import { describe, expect, it } from 'vitest';
import { styleTransferAnyImage } from '../src/style-transfer-any-image';

function flatPlane(width: number, height: number, channels: 1 | 3, value: number): Float32Array {
  const out = new Float32Array(width * height * channels);
  out.fill(value);
  return out;
}

describe('AdaIN adapter surface', () => {
  it('falls back to classical result shape when backend is omitted', async () => {
    const width = 8;
    const height = 8;
    const content = flatPlane(width, height, 3, 0.2);
    const style = flatPlane(width, height, 3, 0.8);
    const result = await styleTransferAnyImage(
      { data: content, width, height, channels: 3 },
      { data: style, width, height, channels: 3 },
      { method: 'adain-adapter' },
    );
    expect(result.methodUsed).toBe('adain-adapter');
    expect(result.stylized.length).toBe(width * height * 3);
  });

  it('uses backend output when provided', async () => {
    const width = 8;
    const height = 8;
    const content = flatPlane(width, height, 1, 0.2);
    const style = flatPlane(width, height, 1, 0.8);
    const result = await styleTransferAnyImage(
      { data: content, width, height, channels: 1 },
      { data: style, width, height, channels: 1 },
      { method: 'adain-adapter' },
      {
        async run(req) {
          const out = new Float32Array(req.width * req.height * req.channels);
          out.fill(0.42);
          return out;
        },
      },
    );
    expect(result.methodUsed).toBe('adain-adapter');
    expect(result.stylized[0]).toBeCloseTo(0.42, 5);
  });
});
